function solve(n, edges, k) {
    if (edges.length === 0) {
        return 0;
    }
    edges.sort((a, b) => a[2] - b[2]);
    let low = 0;
    let high = edges[edges.length - 1][2];
    let answer = high;

    function find(parent, x) {
        while (parent[x] !== x) {
            parent[x] = parent[parent[x]]; // path compression
            x = parent[x];
        }
        return x;
    }

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let parent = Array(n).fill().map((_, i) => i);
        for (let [u, v, w] of edges) {
            if (w <= mid) {
                let rootU = find(parent, u);
                let rootV = find(parent, v);
                if (rootU !== rootV) {
                    parent[rootV] = rootU;
                }
            }
        }

        let roots = new Set();
        for (let i = 0; i < n; i++) {
            roots.add(find(parent, i));
        }
        let components = roots.size;
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}
